//! FS server seeded from the build-time **fs-image** (`workload=stitch-fs`).
//!
//! Identical to `fs-server` but starts from a [`RamFs::seeded`] populated with
//! the files baked under `fs-image/` at build time (the `SEED` manifest the
//! build script generates). A distinct binary so the plain `fs` workload keeps
//! an empty filesystem — the two run on separate boots with separate images.

#![no_std]
#![no_main]

use ramfs::RamFs;
use snitchos_user::entry;

// `SEED: &[(&str, &[u8], &[(&str, &[u8])])]` — generated by build.rs from the
// `fs-image/` dir; each entry carries content plus any extracted xattrs (a
// program's `user.iface` manifest).
include!(concat!(env!("OUT_DIR"), "/fs_seed.rs"));

#[entry]
fn main() {
    fs::serve(RamFs::seeded_with_xattrs(SEED))
}
